1	/**
2	 * Prompt assembly for the RAG chat path.
3	 *
4	 * Composes the system prompt (persona + retrieval grounding instructions +
5	 * a `<retrieved_context>` block) and the user/assistant message sequence
6	 * sent to Claude. Token budgeting keeps the request within the model's
7	 * context window with margin for the response.
8	 *
9	 * Budget rules (see §B3 of P07):
10	 *   - 4000 tokens reserved for the response
11	 *   - persona / history / user message use their actual token cost
12	 *   - the remainder is the retrieved-context budget
13	 *   - chunks that don't fit are dropped lowest-score-first (i.e. we keep
14	 *     the highest-scoring chunks until the budget runs out)
15	 */
16	import { countTokens } from "@anthropic-ai/tokenizer";
17	
18	import type { Retrieved } from "@/lib/llm/retriever";
19	
20	const DEFAULT_MAX_CONTEXT_TOKENS = 16000;
21	const RESPONSE_RESERVE_TOKENS = 4000;
22	const HISTORY_TURNS_KEPT = 6;
23	
24	const INSTRUCTION = `
25	
26	You answer using ONLY the retrieved context below when making claims about the speaker's specific work, opinions, or experiences. If the context does not support an answer, say so. Do not fabricate.
27	
28	Cite each retrieved chunk you use by its [id]. Place citations inline immediately after the claim they support.
29	
30	Voice: write in the speaker's voice. The retrieved chunks are samples of that voice; mirror their cadence, register, and word choice.`;
31	
32	export type AssembledPrompt = {
33	  system: string;
34	  messages: { role: "user" | "assistant"; content: string }[];
35	  citations: { id: string; chunkId: string; snippet: string }[];
36	  tokenBudget: { used: number; max: number };
37	};
38	
39	export interface AssemblePromptArgs {
40	  persona: string;
41	  retrieved: Retrieved[];
42	  history: { role: "user" | "assistant"; content: string }[];
43	  userMessage: string;
44	  maxContextTokens?: number;
45	}
46	
47	export async function assemblePrompt(
48	  args: AssemblePromptArgs
49	): Promise<AssembledPrompt> {
50	  const max = args.maxContextTokens ?? DEFAULT_MAX_CONTEXT_TOKENS;
51	
52	  const trimmedHistory = args.history.slice(-HISTORY_TURNS_KEPT);
53	
54	  const personaTokens = countTokens(args.persona);
55	  const instructionTokens = countTokens(INSTRUCTION);
56	  const historyTokens = trimmedHistory.reduce(
57	    (sum, m) => sum + countTokens(m.content),
58	    0
59	  );
60	  const userMessageTokens = countTokens(args.userMessage);
61	
62	  const fixedTokens =
63	    personaTokens + instructionTokens + historyTokens + userMessageTokens;
64	  const availableForRetrieved = Math.max(
65	    0,
66	    max - RESPONSE_RESERVE_TOKENS - fixedTokens
67	  );
68	
69	  const sorted = [...args.retrieved].sort((a, b) => b.score - a.score);
70	
71	  type Fitted = { id: string; chunk: Retrieved; rendered: string };
72	  const fitted: Fitted[] = [];
73	
74	  // Reserve token cost for the wrapper tags around the retrieved block so
75	  // we don't underestimate. Empty when no chunks are present.
76	  const wrapperTokens =
77	    sorted.length > 0
78	      ? countTokens("\n\n<retrieved_context>\n</retrieved_context>")
79	      : 0;
80	
81	  let usedRetrievedTokens = 0;
82	  for (const r of sorted) {
83	    const id = `c${fitted.length + 1}`;
84	    const rendered = renderChunk(id, r);
85	    const renderedTokens = countTokens(rendered + "\n\n");
86	    if (
87	      wrapperTokens + usedRetrievedTokens + renderedTokens <=
88	      availableForRetrieved
89	    ) {
90	      fitted.push({ id, chunk: r, rendered });
91	      usedRetrievedTokens += renderedTokens;
92	    } else {
93	      // Stop on first miss: dropping a higher-scoring chunk to fit a
94	      // lower-scoring one would violate "drop lowest-score-first".
95	      break;
96	    }
97	  }
98	
99	  let system = args.persona + INSTRUCTION;
100	  if (fitted.length > 0) {
101	    system += "\n\n<retrieved_context>\n";
102	    for (const { rendered } of fitted) {
103	      system += rendered + "\n\n";
104	    }
105	    system += "</retrieved_context>";
106	  }
107	
108	  const messages: { role: "user" | "assistant"; content: string }[] = [
109	    ...trimmedHistory,
110	    { role: "user", content: args.userMessage },
111	  ];
112	
