31	describe("assemblePrompt", () => {
32	  const persona = "You are an assistant who speaks in the voice of M.Q.";
33	
34	  it("produces a well-formed system prompt with no retrieved block when retrieved is empty", async () => {
35	    const out = await assemblePrompt({
36	      persona,
37	      retrieved: [],
38	      history: [],
39	      userMessage: "hello",
40	    });
41	    expect(out.system).toContain(persona);
42	    expect(out.system).toContain("You answer using ONLY");
43	    expect(out.system).not.toContain("<retrieved_context>");
44	    expect(out.citations).toEqual([]);
45	    expect(out.messages).toEqual([{ role: "user", content: "hello" }]);
46	    expect(out.tokenBudget.max).toBe(16000);
47	    expect(out.tokenBudget.used).toBeGreaterThan(0);
48	  });
49	
50	  it("renders retrieved chunks with sequential [c1], [c2], ... ids", async () => {
51	    const retrieved = [
52	      makeRetrieved({ id: "alpha", score: 0.9, text: "alpha body" }),
53	      makeRetrieved({ id: "beta", score: 0.8, text: "beta body" }),
54	      makeRetrieved({ id: "gamma", score: 0.7, text: "gamma body" }),
55	    ];
56	    const out = await assemblePrompt({
57	      persona,
